window.__QUIZ_DATA__=[{"id":"theory>Chemistry>2004>1>a>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.","question":"Mention two types of bond present in the ammonium ion.","images":[],"marking_scheme":"Covalent bond and Dative bond  Covalent bond is present in the formation of ammonia (NH3) while Dative bond is present in the formation of ammonium ion (NH4+).","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>1>a>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMICAL BONDS : IONIC COMPOUNDS","question":"Give three characteristic properties of electrovalent compounds.","images":[],"marking_scheme":"Characteristics of Electrovalent Compounds  - They have high boiling and melting points.  - They are soluble in water and insoluble in non-polar solvents like petrol, benzene etc.  - They usually conduct in aqueous or molten form and will not conduct in solid state.  - Reactions involving ionic compounds in aqueous solutions are very fast.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2004>1>a>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : CHEMICAL SYMBOLS","question":"State two differences between chemical reactions and nuclear reaction.","images":[],"marking_scheme":"Chemical ReactionNuclear Reactions- Outermost electrons of atoms are usually rearrangedNucleus of atoms are usually involved- Mass is conserved- There is mass change- Are usually influenced by temperature and catalyst- Unaffected by temperature and catalyst.- Not usually accompanied by large amount of heat- Large amount of heat is usually involved.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2004>1>b>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"","topic":"STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION","question":"Two element represented by the letters X and Y have atomic numbers 9 and 12 respectively.    Write the electronic configuration of X using the s, p, d, f notation.","images":[],"marking_scheme":"9X &nbsp &nbsp 12Y    9X - 1s2 2s22p5  12Y - 1s2 2s2 2p6 3s2    The above is achieved using Aufbau's principle.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2004>1>b>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE","question":"Two element represented by the letters X and Y have atomic numbers 9 and 12 respectively.  To what group does Y belong in the periodic table?","images":[],"marking_scheme":"12Y -   2, 8, 2  K &nbsp L &nbsp M  The valence shell i.e. shell M has two electrons on it. Therefore, Y belongs to group 2 of the periodic table.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>1>b>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"","topic":"STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.","question":"Two element represented by the letters X and Y have atomic numbers 9 and 12 respectively.  Write the formula of the compound formed when X combines with Y.","images":["data:image/png;base64,"],"marking_scheme":"YX2    9X - 2, 7 ionizes by gaining one electron, thereby becoming X-    12Y - 2, 8, 2 ionizes by losing two electrons, thereby becoming Y2+","marks":"4","difficulty":"2"},{"id":"theory>Chemistry>2004>1>b>iv","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Two element represented by the letters X and Y have atomic numbers 9 and 12 respectively.  Explain why X is a good oxidizing agent.","images":[],"marking_scheme":"An oxidizing agent is a substance which oxidizes other substance and itself is reduced. Reduction is gain of electron, and X is reduced by gaining one electron. Therefore, X is a strong oxidizing agent.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2004>1>b>v","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"v","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Two element represented by the letters X and Y have atomic numbers 9 and 12 respectively.  State with reason, whether Y would be expected to form acidic or basic oxide.","images":[],"marking_scheme":"Y will form a basic oxide since its a metal. Bases are metallic oxide, metallic hydroxides and aqueous ammonia.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2004>1>c>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"FINAL","topic":"STRUCTURE OF THE ATOM : PARTICULATE NATURE OF MATER: PHYSICAL AND CHEMICAL CHANGES.","question":"Balance this nuclear equations and identify the particles represented by X and Y.    146C \u2192 X + 147N","images":[],"marking_scheme":"146C \u2192 abX + 147N  14 = a + 14  14 - 14 = a  0 = a  \u2234 a = 0     6 = b + 7  6 - 7 = b  -1 = b  \u2234 b = -1    0-1X represents electron i.e 0-1e. Therefore, X is a beta particle.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>1>c>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"FINAL","topic":"STRUCTURE OF THE ATOM : PARTICULATE NATURE OF MATER: PHYSICAL AND CHEMICAL CHANGES.","question":"Balance this nuclear equations and identify the particles represented by X and Y.  147N + Y \u2192 11H + 178O","images":[],"marking_scheme":"147N + mNY \u2192 11H + 178O    14 + m = 1 + 17  14 + m = 18  m = 18 - 14  m = 4    7 + n = 1 + 8  7 + n = 9  n = 9 - 7  n = 2    42Y represent Helium nucleus i.e 42He.  Therefore, Y is alpha particle.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>1>d>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS","question":"Consider the following list of substances:  Carbon (IV) oxide, hydrogen, zinc, sulphur, methane, potassium and mercury.  From the list above, state the:    elements that are metals.","images":[],"marking_scheme":"Zinc, potassium and mercury are metals","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2004>1>d>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STATES OF MATTER : GASES","question":"Consider the following list of substances:  Carbon (IV) oxide, hydrogen, zinc, sulphur, methane, potassium and mercury.  From the list above, state the:  compounds that are gases at room temperature.","images":[],"marking_scheme":"Carbon(IV)oxide, hydrogen and methane are gases at room temperature.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2004>1>d>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : CARBON","question":"Consider the following list of substances:  Carbon (IV) oxide, hydrogen, zinc, sulphur, methane, potassium and mercury.  From the list above, state the:  non-metals that are solids at room temperature.","images":[],"marking_scheme":"Sulphur is solid at room temperature.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2004>2>a>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STATES OF MATTER : KINETIC THEORY OF MATTER.","question":"State two assumptions of the kinetic theory of gases.","images":[],"marking_scheme":"Assumptions of the Kinetic Theory of Gases  - A gas is composed of a large number of identical molecules which move at different speeds.  - The forces of attraction and repulsion between the molecules are small and negligible.  - The total volume occupied by the gas molecules is negligible compared to the volume of the container.  - The collision of the gas molecules with one another and with the walls of the container is perfectly elastic.  - The temperature of the gas is a measure of the average kinetic energy of the molecules.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2004>2>a>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STATES OF MATTER : CHANGES OF STATE OF MATTER.","question":"When some solids are heated, they change directly into the gaseous state. What name is given to this phenomenon?","images":[],"marking_scheme":"This phenomenon is called Sublimation.  Sublimation is a conversion of substance from solid phase directly to gaseous phase without passing through the liquid phase.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>2>a>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.","question":"List two substances which exhibit the phenomenon referred to in (a)(ii) above.","images":[],"marking_scheme":"- Iodine crystal  - Ammonium chloride  - Dry ice (solid carbon (IV) oxide)  - Camphor","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2004>2>a>iv","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"Write an expression to show the mathematical relationship between the rate of diffusion of a gas and its vapour density.","images":[],"marking_scheme":"The rate of diffusion of a gas is inversely proportional to the square root of its molecular mass or density at constant temperature and pressure.  R\u03b11&radic;\u03c1&nbsp;  R=k&radic;\u03c1&nbsp;  R is the rate of diffusion  \u03c1 is the density  K is constant","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2004>2>b>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"Consider the following equilibrium reaction:  3Fe(s) + 4H2O(g) \u21cc Fe3O4(s) + 4H2(g)  \u0394H = -150KJ mol-1    Explain the effect of the following factors on the position of equilibrium;    Decrease in temperature.","images":[],"marking_scheme":"3Fe(s) + 4H2O(g) \u21cc Fe3O4(s) + 4H2(g)  \u0394H = -150KJ mol-1    Effect of decrease in temperature  - Increase in temperature favours a side that is endothermic while decrease in temperature favours a side that is exothermic. Since the reaction is exothermic for the forward reaction, decrease in temperature makes the equilibrium position to shift to the right, hence, there is more formation of the product.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>2>b>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"Consider the following equilibrium reaction:  3Fe(s) + 4H2O(g) \u21cc Fe3O4(s) + 4H2(g)  \u0394H = -150KJ mol-1    Explain the effect of the following factors on the position of equilibrium;  Increase in pressure.","images":[],"marking_scheme":"Effect of increase in pressure  - Increase in pressure favours a side with lesser number of moles of gaseous molecules while decrease in pressure favours a side with higher number of moles of gaseous molecules. The reaction has equal number of molecules of gaseous molecules on each side i.e 4 moles each. Therefore, pressure has no effect on the reaction.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>2>b>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"Consider the following equilibrium reaction:  3Fe(s) + 4H2O(g) \u21cc Fe3O4(s) + 4H2(g)  \u0394H = -150KJ mol-1    Explain the effect of the following factors on the position of equilibrium;  Removal of hydrogen.","images":[],"marking_scheme":"- Removal of hydrogen decreases the concentration of the product side, therefore, the equilibrium position will shift to the right to favour the production of hydrogen.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>2>c>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"Three beakers labelled P, Q and S each contained zinc metal of the same mass but different forms. P contained a length of zinc rod, Q contained zinc dust while S contained zinc foil. 100cm3 of 5.0 mol dm-3 hydrochloric acid was added to each beaker to react with all the zinc.    State the order in which the reaction came to completion in beakers P, Q and S starting with the fastest.","images":[],"marking_scheme":"Order of reactivity from the fastest:  Q, S and P","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2004>2>c>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"Three beakers labelled P, Q and S each contained zinc metal of the same mass but different forms. P contained a length of zinc rod, Q contained zinc dust while S contained zinc foil. 100cm3 of 5.0 mol dm-3 hydrochloric acid was added to each beaker to react with all the zinc.  Give reason for your answer in (c) (i) above.","images":[],"marking_scheme":"The zinc duct has the largest surface area than the zinc foil. The zinc foil also has a larger surface area than the zinc rod. This is why the reaction is fastest in the beaker Q with the zinc dust and least in the beaker P with the zinc rod.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2004>2>c>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Three beakers labelled P, Q and S each contained zinc metal of the same mass but different forms. P contained a length of zinc rod, Q contained zinc dust while S contained zinc foil. 100cm3 of 5.0 mol dm-3 hydrochloric acid was added to each beaker to react with all the zinc.  Write an equation to represent the reaction between zinc and the hydrochloric acid.","images":[],"marking_scheme":"Zn(s) + 2HCl(aq) \u2192 ZnCl2(aq) + H2(g)","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2004>2>d>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : CONCEPT OF PH","question":"What is meant by pH of a solution?","images":[],"marking_scheme":"pH is a measure of the acidity or alkalinity of a solution. It is a measure of hydrogen ion concentration in a solution.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2004>2>d>ii>I","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"State with reason in each case whether the pH would increase, decrease or remain constant if the following experiments were carried out.  - Neutralizing bench HNO3;","images":[],"marking_scheme":"- The pH value of HNO3 will increase because its hydrogen ion concentration will reduce as a result of neutralization.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>2>d>ii>II","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : CONCEPT OF PH","question":"State with reason in each case whether the pH would increase, decrease or remain constant if the following experiments were carried out.  - Diluting 25.0cm3 of a given NaOH solution to 100.0cm3","images":[],"marking_scheme":"- When NaOH becomes diluted, its concentration reduces, this will reduce the pH value of NaOH","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>2>d>ii>III","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"III","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : CONCEPT OF PH","question":"State with reason in each case whether the pH would increase, decrease or remain constant if the following experiments were carried out.  - Concentrating a solution of NaCl.","images":[],"marking_scheme":"-. When a solution of NaCl has its concentration increased, the pH value remains constant since NaCl is a neutral salt.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>3>a>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"","topic":"ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY","question":"Draw an energy profile diagram to illustrate a catalysed exothermic reaction and label parts of the curves representing the following:    activated complex (without catalyst)","images":["data:image/png;base64,"],"marking_scheme":"A is activated complex (without catalyst)","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>3>a>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY","question":"Draw an energy profile diagram to illustrate a catalysed exothermic reaction and label parts of the curves representing the following:  activation energy (with catalyst).","images":[],"marking_scheme":"B is activation energy (with catalyst)","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>3>a>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY","question":"Draw an energy profile diagram to illustrate a catalysed exothermic reaction and label parts of the curves representing the following:  enthalpy change.","images":[],"marking_scheme":"\u0394H is enthalpy change which is negative since the heat of the product is less than that of the reactant.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>3>b>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : HYDROGEN","question":"Give the reasons for this observation    A balloon filled with hydrogen becomes deflated faster than a balloon filled with air under the same conditions.","images":[],"marking_scheme":"This occurs because hydrogen molecules are smaller than the molecules of oxygen and Nitrogen in air. Therefore, hydrogen molecules escape readily in the small and tiny holes in the thin rubber of the balloon.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>3>b>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Give the reasons for this observation  Hydrogen peroxide decomposes slowly at room temperature but when a pinch of MnO2 is added, bubbles form rapidly.","images":[],"marking_scheme":"The MnO2 serves as catalyst, thereby speeding up the reaction which leads to the formation of bubbles rapidly.   2H2O2(l) \u2192 2H2O(l) + O2(g)  The bubbles is the oxygen formed.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>3>b>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Give the reasons for this observation  A solution of hydrogen chloride gas in methylbenzene has no effect on litmus but a solution of the gas in water turns blue litmus paper red.","images":[],"marking_scheme":"Hydrogen chloride gas in water forms hydrochloric acid (HCl) which turns blue litmus paper red. Hydrogen chloride gas on the other hand is not soluble in methylbenzene, which in turn has no effect on litmus paper.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>3>c>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REDOX REACTIONS : REDOX EQUATIONS","question":"Consider the reaction represented by the following equation:  2MnO-4(aq) + 5C2O2-4 + 16H+(aq) \u2192 2Mn2+(aq) + 8H2O(l) + 10CO2(g)  Write down:    the species undergoing reduction giving reasons.","images":[],"marking_scheme":"2MnO-4(aq) + 5C2O2-4 + 16H+(aq) \u2192 2Mn2+(aq) + 8H2O(l) + 10CO2(g)    Removal of oxygen is reduction. Therefore MnO4- has undergone reduction since becomes Mn2+, which is without oxygen. In other words, MnO4- has undergone reduction since the oxidation number of manganese in it is +7 which later become +2 in Mn2+ which is a decrease.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2004>3>c>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"","topic":"REDOX REACTIONS : REDOX EQUATIONS","question":"Consider the reaction represented by the following equation:  2MnO-4(aq) + 5C2O2-4 + 16H+(aq) \u2192 2Mn2+(aq) + 8H2O(l) + 10CO2(g)  Write down:  the reducing agent giving reasons;","images":[],"marking_scheme":"A reducing agent reduces other substance while itself is oxidized. Hence, the reducing agent is C2O42- since it is being oxidized. This is because the oxidation number of carbon in it is +3 which later increases to +4 in CO2.    MnO4-  Mn + (-2 \u00d7 4) = -1  Mn - 8 = -1  Mn = 8 - 1  Mn = +7    C2O42-  (C \u00d7 2) + (-2 \u00d7 4) = -2  2C - 8 = -2  2C = 8 - 2  2C = 6  C=62  C = +3    CO2  C + (-2 \u00d7 2) = 0  C - 4 = 0  C = +4","marks":"4","difficulty":"3"},{"id":"theory>Chemistry>2004>3>c>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"","topic":"REDOX REACTIONS : REDOX EQUATIONS","question":"Consider the reaction represented by the following equation:  2MnO-4(aq) + 5C2O2-4 + 16H+(aq) \u2192 2Mn2+(aq) + 8H2O(l) + 10CO2(g)  Write down:  the reduction half equation.","images":[],"marking_scheme":"Reduction half equation  MnO4-(aq) + 8H+(aq) + 5e- \u2192 Mn2+(aq) + 4H2O(l)","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>3>c>iv","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"REDOX REACTIONS : REDOX EQUATIONS","question":"Consider the reaction represented by the following equation:  2MnO-4(aq) + 5C2O2-4 + 16H+(aq) \u2192 2Mn2+(aq) + 8H2O(l) + 10CO2(g)  Write down:  one observation made during the reaction.","images":[],"marking_scheme":"There is decolourization of tetraoxomanganate (VII) solution and there is formation of effervescence due to the formation carbon (IV) oxide gas.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>3>d>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROCHEMICAL CELLS","question":"What is an electrochemical cell?","images":[],"marking_scheme":"An electrochemical cell is a device made by placing metallic electrodes into an electrolyte which is capable of generating electrical energy from a chemical reaction.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2004>3>d>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"State three differences between an electrochemical cell and an electrolytic cell.","images":[],"marking_scheme":"Differences between an electrochemical cell and an electrolytic cell  Electrochemical CellElectrolyte Cell- It converts chemical energy to electrical energy.- It converts electrical energy to chemical energy- Cathode is the positive electrode.- Cathode is the negative electrode.- Anode is the negative electrode.- Anode is the positive electrode.- It does not need any external current for operation.- It needs external current to operate.","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2004>4>a>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"Methane reacts with chlorine under certain condition to produce tetrachloromethane.    State the condition for the reaction.","images":[],"marking_scheme":"The reaction takes place in the presence of ultraviolet ray or sunlight.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>4>a>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"Methane reacts with chlorine under certain condition to produce tetrachloromethane.  Name the type of reaction.","images":[],"marking_scheme":"The reaction is substitution reaction, where the hydrogen atom(s) of alkanes is/are being replaced by univalent atom(s) or group(s).","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>4>a>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"Methane reacts with chlorine under certain condition to produce tetrachloromethane.  Give two uses of methane.","images":[],"marking_scheme":"Uses of Methane  - It is used in gas cookers.  - It is used to manufacture organic chemicals.  - It is used in gas fired power stations.  - It is used as a rocket fuel instead of kerosene.","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2004>4>a>iv","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"Methane reacts with chlorine under certain condition to produce tetrachloromethane.  Name one major natural source of methane.","images":[],"marking_scheme":"One major natural source of methane  - Natural gas","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2004>4>b>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS","question":"Mention one similarity between the reaction of ethanol with sodium and that of sodium with water.","images":[],"marking_scheme":"Both reactions liberate hydrogen gas  2Na(s) + 2C2H5OH(l) \u2192 2C2H5ONa + H2(g)  Na(s) + H2O(l) \u2192 NaOH + H2(g)","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2004>4>b>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION","question":"Write the structure of two isomers of C3H8O.","images":["data:image/png;base64,"],"marking_scheme":"C3H8O is propanol which can be written as C3H7OH. It has two two isomers which are propan - 1 - ol and propan - 2 - ol.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>4>b>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"Differentiate between a fine chemical and a heavy chemical.","images":[],"marking_scheme":"A fine chemical is compound made in relatively small quantity and in a comparatively pure state.  A heavy chemical is a chemical made on a very large scale and are used extensively in industries.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>4>b>iv","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"Give one example of each in (b) (iii) above.","images":[],"marking_scheme":"Examples of fine chemicals:  Drugs, perfumes, addictives, dyes etc  Examples of heavy chemicals:  H2SO4, NaOH, NH3, HCl, NaCO3 etc.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2004>4>c>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS","question":"Two compounds X and Y have the same percentage composition by mass of 92.3% carbon and 7.7% hydrogen. Calculate the    empirical formula of X and Y.","images":[],"marking_scheme":"C - 92.3%  H - 7.7%    CH% by mass of element72.37.7Mole 72.3/12    7.697.7/1    7.7Divide through by the smaller number of mole    7.69/7.69    17.7/7.69    1  The empirical formula for X and Y is CH since both have the same percentage composition by mass.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>4>c>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS","question":"Two compounds X and Y have the same percentage composition by mass of 92.3% carbon and 7.7% hydrogen. Calculate the   molecular formula of each compound if molar mass of X is 26g and Y is 78g.","images":[],"marking_scheme":"Molar mass of X = 26g  Molar mass of Y = 78g  To calculate the molecular formula for X  (CH)n = 26  C = 12, H = 1  (12 + 1)n = 26  13n = 26  n=2613  n = 2  \u2234 The molecular formula of X is C2H2  To calculate the molecular formular for Y  (CH)n = 78  (12 + 1)n = 78  13n = 78  n=7813  n = 6  \u2234 The molecular formula for Y is C6H6.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>4>d>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : PROTEINS","question":"A protein is boiled for a long time with dilute HCl and a reaction occurred.    State the type of reaction that occurred.","images":[],"marking_scheme":"Boiling a protein in hydrochloric acid will break down the protein down into its constituent amino acids.  The reaction is hydrolysis reaction.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>4>d>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : PROTEINS","question":"A protein is boiled for a long time with dilute HCl and a reaction occurred.  Name the major product formed.","images":[],"marking_scheme":"The major product formed is amino acid.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2004>4>d>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : PROTEINS","question":"A protein is boiled for a long time with dilute HCl and a reaction occurred.  Give the functional groups present in (d)(ii) above.","images":["data:image/png;base64,"],"marking_scheme":"Amino acids contain amine ( - NH2) and carboxyl group ( - COOH) as their functional group.    carboxyl group","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>5>a>i>I","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"I","group":"","topic":"NON METALS AND THEIR COMPOUNDS : WATER AND SOLUTION","question":"State one physical method and one chemical method in each case by which the following can be removed   - Permanent hardness in water;","images":[],"marking_scheme":"- For permanent hardness  - The chemical method used is by using Na2CO3.  CaSO4(aq) + Na2CO3(aq) \u2192 Na2SO4(aq) + CaCO3(s)    - The physical method which can be used is ion exchange resin.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2004>5>a>i>II","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"II","group":"","topic":"STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES","question":"State one physical method and one chemical method in each case by which the following can be removed   - A suspension of CaCO3 in water.","images":[],"marking_scheme":"- A suspension of CaCO3 in water  - The chemical method is by passing excess CO2 through the solution to form a clear solution [Ca(HCO3)2].    III. Physical method is by filtration and leaving the residue behind.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2004>5>a>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : WATER AND SOLUTION","question":"Give one disadvantage of hard water.","images":[],"marking_scheme":"Disadvantages of Hard water  - It does not form lather readily with soap.  - It causes furring of kettles and boilers.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2004>5>b>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.","question":"Explain this observation    Crystals of washing soda become powdery on exposure to air for a long time.","images":[],"marking_scheme":"The crystal of washing soda become powdery on exposure to air for a long time because it has lost its water of crystallization to the atmosphere.  This is known as efflorescence.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>5>b>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES","question":"Explain this observation  The concentration of chloride ions in 0.02 mol dm-3 calcium chloride solution is not the same as in 0.02 mol dm-3 sodium chloride solution.","images":[],"marking_scheme":"This is because sodium chloride is a strong salt which ionizes completely in water but calcium chloride is a weak salt which ionizes partially in water. Therefore, sodium chloride gives more chloride ion in solution than calcium chloride.  Each mole of CaCl2 ionizes to give two moles of Cl- whereas one mole of NaCl  produces one mole of Cl-  on ionization","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>5>b>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS","question":"Explain this observation  Iron filings corrode faster than iron nails of the same mass.","images":[],"marking_scheme":"This is because iron fillings have larger surface with air, hence it reacts faster with moisture than iron nails of the same mass which have smaller surface area.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2004>5>c>i>I","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Classify each of the following oxides as acidic, basic, neutral or amphoteric.  - ZnO","images":[],"marking_scheme":"- Amphoteric Oxide, ZnO: It reacts as either an acid or as a base.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>5>c>i>II","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : BASES","question":"Classify each of the following oxides as acidic, basic, neutral or amphoteric.  - CO","images":[],"marking_scheme":"- Neutral Oxide, CO: It neither shows basic nor acidic properties.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>5>c>i>III","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"III","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Classify each of the following oxides as acidic, basic, neutral or amphoteric.  - NO2","images":[],"marking_scheme":"- Acidic Oxide, NO2: It forms acid when dissolved in water.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>5>c>ii>I","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"I","group":"","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Give the formula of the acid anhydride of each of the following:  - H2CO3","images":[],"marking_scheme":"Acid anhydrides are oxides of non-metals which react with water to form an acid.  - The acid anhydride of H2CO3 is CO2  CO2 + H2O \u2192 H2CO3","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>5>c>ii>II","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"II","group":"","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Give the formula of the acid anhydride of each of the following:  - H2SO4","images":[],"marking_scheme":"-The acid anhydride of H2SO4 is SO3  SO3 + H2O \u2192 H2SO4","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>5>c>iii>I","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"I","group":"","topic":"ACIDS, BASES AND SALTS : SALTS","question":"Give the IUPAC name of the following salts:  - CoCl2","images":[],"marking_scheme":"CoCl2  The oxidation number of Cl is -1.  Co + (-1 \u00d7 2) = 0  Co - 2 = 0  Co = +2  Cobalt (II) chloride","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>5>c>iii>II","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"II","group":"FINAL","topic":"ACIDS, BASES AND SALTS : SALTS","question":"Give the IUPAC name of the following salts:  - Mg(NO3)2","images":[],"marking_scheme":"Mg(NO3)2  The oxidation number of Mg and O are +2 and -2 respectively.  +2 + 2[N + (-2 \u00d7 3)] = 0  2 + 2(N - 6) = 0  2 + 2N - 12 = 0  2N = 12 - 2  2N = 10  N=102  N = +5  Magnesium trioxonitrate (V) salt.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>5>d>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"Mention one pollutant associated with depletion of ozone layer in the atmosphere.","images":[],"marking_scheme":"Pollutant associated with depletion  - chlorofluorocarbon (CFC).","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2004>5>d>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"FINAL","topic":"STATES OF MATTER : GASES","question":"Calculate the volume occupied by 0.125 mole of oxygen at 27\u00b0C and a pressure of 2.20 \u00d7 105 Nm-2  [1 mole of gas occupies 22.4 dm3 at s.t.p.; standard pressure = 1.01 \u00d7 105 Nm-2]    Leave your answer in 2 decimal places 'a.bc'","images":[],"marking_scheme":"V = ?, n = 0.125, T = 27\u00b0C = 27 + 273 = 300K  P = 2.02 \u00d7 105 Nm-2, R = 8.314 Jmol-1K-1  Recall,  PV = nRT  V=nRTP  =0.125 \u00d7 8.314 \u00d7 3002.02 \u00d7 105 = 0.00154m3  But 1000dm3 = 1m3  x = 0.00154m3  x = 1000 \u00d7 0.00154  x = 1.54dm3  The volume is 1.54 dm3","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>5>d>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : OXYGEN","question":"State one process used for the industrial preparation of oxygen.","images":[],"marking_scheme":"Industrial preparation of oxygen  - Cryogenic fractional distillation of air.  - Regenerative differential physical adsorption by zeolites.  - Water electrolysis.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2004>6>a>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.","question":"Give the reason why copper turnings dissolve in AgNO3 solution but remain insoluble in Pb(NO3)2 solution.","images":[],"marking_scheme":"Copper turnings dissolve in AgNO3 solution because it is more electropositive than silver and therefore displaces silver ions from AgNO3 solution. But in the case of Pb(NO3)2 solution, copper turnings remain insoluble since lead is more electropositive than copper and hence, it won't be able to displace it in the solution.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>6>a>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"FINAL","topic":"METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.","question":"Copper turnings of mass 1.06g were placed in 250cm3 of 0.20 mol dm-3 AgNO3.  Calculate the amount of silver ions present. [Cu = 63.5]    Leave your answer in 3 decimal places 'a.bcd'","images":[],"marking_scheme":"Cu(s) + 2Ag2+(aq) \u2192 Ag(s) + Cu2+(aq)  m. of Cu = 1.06g; V of AgNO3 = 250cm3  C of AgNO3 = 0.20 moldm-3  n.ofCu=mMM  =1.0663.5=0.017mole  number of mole of AgNO3 = CV  \u21d20.20\u00d72501000  \u21d2 0.05 mole    Cu(s) + 2Ag+(aq) \u2192 Ag(s) + Cu2+(aq)  1 &nbsp &nbsp 2 &nbsp &nbsp &nbsp 1 &nbsp &nbsp 1  0.017 &nbsp &nbsp 0.05  The limited reagent is Cu. Hence, 0.017mol of Cu is used for the calculation.  1 mole of Cu \u2192 2 moles of Ag+   0.017 \u2192 x  x = 2 \u00d7 0.017  x = 0.034mole  \u2234 The amount of silver ions present is 0.034mole","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>6>a>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Determine whether all the copper in (a)(ii) above will dissolve in the solution.  The equation for the reaction is Cu(s) + 2Ag2+(aq) \u2192 Ag(s) + Cu2+(aq)","images":[],"marking_scheme":"Yes, all the copper will dissolve in the solution since it is the limited reactant.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2004>6>b>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"List three chemical properties of acids.","images":[],"marking_scheme":"Chemical Properties of Acids  - Reaction of acid with metal: Acids react with reactive metals to liberate hydrogen gas  Mg(s) + 2HCl(aq) \u2192 MgCl2(aq) + H2(g)    - Acid reacting with Bases: Acids react bases to form a salt and water only.    - Acid reacting with carbonates: Acids react with carbonate or hydrogen carbonate to form salt, water and carbondioxide gas   CaCO3(s) + 2HCl(aq) \u2192 CaCl2(aq) + H2O(l) + CO2(g)","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2004>6>b>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : NITROGEN","question":"Give two large scale uses of HNO3","images":[],"marking_scheme":"Uses of HNO3  - It is used for the production of fertilizers, dyes, drugs  - It is highly used in the manufacturing of explosives.  - It is used as a chemical reagent to identify various other metals.  - It is a component of solid rocket fuels and acts as an oxidizer.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>6>b>iii>I","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"I","group":"","topic":"CHEMICAL BONDS : IONIC COMPOUNDS","question":"Write an equation for the action of heat on each of the following compounds:  - Pb(NO3)2","images":[],"marking_scheme":"-  2Pb(NO3)2 \u2192 2PbO + 4NO2 + O2 (in the presence of heat)","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>6>b>iii>II","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"II","group":"","topic":"CHEMICAL BONDS : IONIC COMPOUNDS","question":"Write an equation for the action of heat on each of the following compounds:  -  AgNO3.","images":[],"marking_scheme":"- 2AgNO3(l) \u2192 2Ag(s) + O2(g) + 2NO2(g)","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>6>c>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : HALOGENS","question":"State what would be observed if a piece of damp blue litmus paper is dropped into a gas jar of chlorine.","images":[],"marking_scheme":"The damp blue litmus paper first turns red and then bleaches it white. This is because chlorine reacts with water to form hydrochloric acid (HCl).","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2004>6>c>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Name the type of reaction which occurs in (c) (i) above.","images":[],"marking_scheme":"It is oxidation reaction.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>6>c>iii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : HALOGENS","question":"Give the property of chlorine which is exhibited in the reaction in (c)(i) above.","images":[],"marking_scheme":"This is because chlorine has a bleaching property as an oxidizing agent.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2004>6>d>i","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL","question":"Name two products obtained directly from the destructive distillation of coal.","images":[],"marking_scheme":"Product of destructive distillation of coal  - coke  - coal tar  - Amino acid liquor  - coal gas","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2004>6>d>ii","subject":"Chemistry","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"Give one use of each product named in (d)(i) above.","images":[],"marking_scheme":"Uses of Coke  - It is used as a reducing agent in the extraction of metals from their ores.  - It is used in making fuel gases like water gas.    Use of Coal tar  - It is used to make soap, fats, perfume etc.    Use of Ammoniacal liquor  - It is used for making fertilizers such as ammonium sulphate etc.    Use of Coal gas  - It is used as industrial fuel.","marks":"1","difficulty":"3"}];